@dataclass
class MitigationPlan:
    risk_id: str
    risk_rating: str           # "critical", "high", "medium", "low"
    tasks: list[MitigationTask] = field(default_factory=list)

    # SLA for mitigation plan completion by rating
    PLAN_SLA_DAYS = {"critical": 30, "high": 60, "medium": 90, "low": None}
    CLOSE_SLA_DAYS = {"critical": 90, "high": 180, "medium": 365, "low": None}

    def plan_due_date(self, risk_identified: date) -> Optional[date]:
        days = self.PLAN_SLA_DAYS.get(self.risk_rating)
        return risk_identified + timedelta(days=days) if days else None

    def close_due_date(self, risk_identified: date) -> Optional[date]:
        days = self.CLOSE_SLA_DAYS.get(self.risk_rating)
        return risk_identified + timedelta(days=days) if days else None

    def overall_status(self) -> MitigationStatus:
        if not self.tasks:
            return MitigationStatus.IDENTIFIED
        statuses = {t.status for t in self.tasks}
        if MitigationStatus.OVERDUE in statuses:
            return MitigationStatus.OVERDUE
        if all(s == MitigationStatus.CLOSED for s in statuses):
            return MitigationStatus.CLOSED
        if all(s in {MitigationStatus.VALIDATED, MitigationStatus.CLOSED} for s in statuses):
            return MitigationStatus.VALIDATED
        if any(s in {MitigationStatus.IN_PROGRESS, MitigationStatus.EVIDENCE} for s in statuses):
            return MitigationStatus.IN_PROGRESS
        return MitigationStatus.ASSIGNED

    def overdue_tasks(self, as_of: date | None = None) -> list[MitigationTask]:
        return [t for t in self.tasks if t.is_overdue(as_of)]

class MitigationTracker:
    """Central tracker for all risk mitigation plans."""

    def __init__(self):
        self._plans: dict[str, MitigationPlan] = {}

    def add_plan(self, plan: MitigationPlan) -> None:
        self._plans[plan.risk_id] = plan

    def get_plan(self, risk_id: str) -> Optional[MitigationPlan]:
        return self._plans.get(risk_id)

    def advance_task(self, risk_id: str, task_id: str,
                     new_status: MitigationStatus,
                     evidence_link: str | None = None) -> None:
        plan = self._plans[risk_id]
        task = next(t for t in plan.tasks if t.task_id == task_id)
        _validate_transition(task.status, new_status)
        task.status = new_status
        if evidence_link:
            task.evidence_links.append(evidence_link)
        if new_status == MitigationStatus.CLOSED:
            task.completion_date = date.today()

    def flag_overdue(self, as_of: date | None = None) -> list[tuple[str, MitigationTask]]:
        """Returns (risk_id, task) pairs for all overdue tasks."""
        overdue = []
        for risk_id, plan in self._plans.items():
            for task in plan.overdue_tasks(as_of):
                task.status = MitigationStatus.OVERDUE
                overdue.append((risk_id, task))
        return overdue

    def dashboard(self) -> dict:
        counts = {s.value: 0 for s in MitigationStatus}
        for plan in self._plans.values():
            counts[plan.overall_status().value] += 1
        return {"total_risks": len(self._plans), **counts}


_VALID_TRANSITIONS = {
    MitigationStatus.IDENTIFIED:  {MitigationStatus.ASSIGNED},
    MitigationStatus.ASSIGNED:    {MitigationStatus.IN_PROGRESS, MitigationStatus.OVERDUE},
    MitigationStatus.IN_PROGRESS: {MitigationStatus.EVIDENCE, MitigationStatus.OVERDUE},
    MitigationStatus.EVIDENCE:    {MitigationStatus.VALIDATED, MitigationStatus.IN_PROGRESS},
    MitigationStatus.VALIDATED:   {MitigationStatus.CLOSED},
    MitigationStatus.OVERDUE:     {MitigationStatus.IN_PROGRESS, MitigationStatus.ASSIGNED},
    MitigationStatus.CLOSED:      set(),
}

def _validate_transition(current: MitigationStatus, next_s: MitigationStatus) -> None:
    if next_s not in _VALID_TRANSITIONS.get(current, set()):
        raise ValueError(f"Invalid transition: {current.value} → {next_s.value}")
